//! # Digital Hadron Collider + Echolocation — runtime mirrors of the Lean specs
//!
//! Mirrors:
//!
//! - `Gnosis.DigitalHadronCollider` — collision events as Bule unit
//!   composition, with conserved score, decay products, and
//!   self-similarity triggering.
//! - `Gnosis.Echolocation` — emit / probe / return round trip; the
//!   contract count after a violation localizes the manifold's wall.
//!
//! Both modules use the cost-algebra primitives from
//! `distributed_inference::cost_algebra` so the chaos engine and the
//! inference runtime share one type system. Strict-by-default
//! enforcement via `Result<_, CostAlgebraViolation>`; advisory
//! callers can use the `*_decision` shapes that don't error.
//!
//! @see open-source/gnosis-math/Gnosis/DigitalHadronCollider.lean
//! @see open-source/gnosis-math/Gnosis/Echolocation.lean

use distributed_inference::cost_algebra::{
    self as ca, BuleyCostAlgebra, BuleyFace, BuleyProjection, CostAlgebra, CostAlgebraViolation,
};

// Mirror of the Lean `ManifoldPhaseCount = Nat`. The cost-algebra runtime in
// distributed-inference uses `u32` for ceilings; this alias makes the
// echolocation/collider vocabulary explicit.
pub type ManifoldPhaseCount = u32;

// ────────────────────────────────────────────────────────────────────
// Digital Hadron Collider
// ────────────────────────────────────────────────────────────────────

/// A collision event: two source carriers + the composed result.
/// Mirrors `Gnosis.DigitalHadronCollider.CollisionEvent`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct CollisionEvent {
    pub source_a: BuleyProjection,
    pub source_b: BuleyProjection,
    pub composed: BuleyProjection,
}

/// Construct a collision event from two carriers. Mirrors
/// `DigitalHadronCollider.collide`.
pub fn collide(a: BuleyProjection, b: BuleyProjection) -> CollisionEvent {
    CollisionEvent {
        source_a: a,
        source_b: b,
        composed: BuleyCostAlgebra::compose(a, b),
    }
}

/// Total energy of the collision: the score of the composed carrier.
/// Equal to `score a + score b` by conservation
/// (`Gnosis.DigitalHadronCollider.collision_conserves_score`).
pub fn collision_energy(e: &CollisionEvent) -> u32 {
    BuleyCostAlgebra::score(e.composed)
}

/// The three decay products: waste-face, action-face, entropy-face
/// projections of the composed carrier. Mirrors
/// `DigitalHadronCollider.DecayProducts`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct DecayProducts {
    pub waste: BuleyProjection,
    pub action: BuleyProjection,
    pub entropy: BuleyProjection,
}

pub fn decay_products(e: &CollisionEvent) -> DecayProducts {
    let c = e.composed;
    DecayProducts {
        waste: BuleyProjection {
            waste: c.waste,
            opportunity: 0,
            diversity: 0,
        },
        action: BuleyProjection {
            waste: 0,
            opportunity: c.opportunity,
            diversity: 0,
        },
        entropy: BuleyProjection {
            waste: 0,
            opportunity: 0,
            diversity: c.diversity,
        },
    }
}

/// Check whether the collision triggers the detector at the given
/// manifold ceiling. Mirrors `DigitalHadronCollider.triggered`. The
/// `Option<u32>` return wraps the corrective-contract count when
/// triggered, `None` when the event is inside the manifold.
pub fn collision_trigger(e: &CollisionEvent, ceiling: ManifoldPhaseCount) -> Option<u32> {
    let energy = collision_energy(e);
    if energy <= ceiling {
        None
    } else {
        Some(energy - ceiling)
    }
}

/// Strict variant: returns `Err` if the collision triggers the
/// detector (over-energy event). Returns the collision event on
/// admission. The application layer can choose strict (reject
/// over-energy collisions) or advisory (use `collision_trigger`).
pub fn require_collision_within_ceiling(
    e: CollisionEvent,
    ceiling: ManifoldPhaseCount,
) -> Result<CollisionEvent, CostAlgebraViolation> {
    match collision_trigger(&e, ceiling) {
        None => Ok(e),
        Some(deficit) => Err(CostAlgebraViolation {
            gate: "hadron-collider-trigger",
            message: format!(
                "Collision energy {} exceeds manifold ceiling {} by {}",
                collision_energy(&e),
                ceiling,
                deficit
            ),
        }),
    }
}

// ────────────────────────────────────────────────────────────────────
// Echolocation
// ────────────────────────────────────────────────────────────────────

/// The result of an emit step. Mirrors
/// `Gnosis.Echolocation.EcholocationEmit`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct EcholocationEmit {
    pub post_emit: BuleyProjection,
    pub emit_score: u32,
}

/// Emit: lift the carrier on a chosen face. Mirrors
/// `Echolocation.emit`. Always increments the carrier's score by
/// exactly one (`Echolocation.emit_score_increment`).
pub fn emit(b: BuleyProjection, face: BuleyFace) -> EcholocationEmit {
    let post = b.clinamen_lift(face);
    EcholocationEmit {
        post_emit: post,
        emit_score: post.score(),
    }
}

/// The result of a probe step. Mirrors
/// `Echolocation.EcholocationReturn`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct EcholocationReturn {
    pub inside: bool,
    pub contract_count: u32,
}

/// Probe: classify a candidate post-emit carrier against a manifold
/// ceiling. Mirrors `Echolocation.probe`.
pub fn probe(post: BuleyProjection, ceiling: ManifoldPhaseCount) -> EcholocationReturn {
    let s = post.score();
    if s <= ceiling {
        EcholocationReturn {
            inside: true,
            contract_count: 0,
        }
    } else {
        EcholocationReturn {
            inside: false,
            contract_count: s - ceiling,
        }
    }
}

/// A full echolocation event: source, face, ceiling, emit, probe,
/// post-return. Mirrors `Echolocation.EcholocationEvent`.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct EcholocationEvent {
    pub source: BuleyProjection,
    pub face: BuleyFace,
    pub ceiling: ManifoldPhaseCount,
    pub emit_result: EcholocationEmit,
    pub probe_result: EcholocationReturn,
    pub post_return: BuleyProjection,
}

/// Run the full round trip: emit, probe, contract back. The post-return
/// carrier closes the loop by the breathing identity. Mirrors
/// `Echolocation.echolocate`.
pub fn echolocate(
    b: BuleyProjection,
    face: BuleyFace,
    ceiling: ManifoldPhaseCount,
) -> EcholocationEvent {
    let e = emit(b, face);
    let p = probe(e.post_emit, ceiling);
    let post = e.post_emit.clinamen_contract(face);
    EcholocationEvent {
        source: b,
        face,
        ceiling,
        emit_result: e,
        probe_result: p,
        post_return: post,
    }
}

/// Strict variant: returns `Err` when the echo reports a violation.
/// Useful when the application wants to refuse to emit into a
/// manifold the source's score would exceed.
pub fn require_echolocation_within_ceiling(
    b: BuleyProjection,
    face: BuleyFace,
    ceiling: ManifoldPhaseCount,
) -> Result<EcholocationEvent, CostAlgebraViolation> {
    let event = echolocate(b, face, ceiling);
    if event.probe_result.inside {
        Ok(event)
    } else {
        Err(CostAlgebraViolation {
            gate: "echolocation-violation",
            message: format!(
                "Echo emit on face {:?} from score {} exceeded ceiling {} by {} contracts",
                face,
                b.score(),
                ceiling,
                event.probe_result.contract_count
            ),
        })
    }
}

// Silence the unused-import warning on `ca` if no other reference is added.
#[allow(dead_code)]
fn _ca_namespace_anchor() -> () {
    let _ = ca::tower_ceilings::HEXON;
}

#[cfg(test)]
mod tests {
    use super::*;
    use distributed_inference::cost_algebra::tower_ceilings;

    // ── Hadron collider ─────────────────────────────────────────────

    #[test]
    fn collision_conserves_score() {
        let a = BuleyProjection {
            waste: 3,
            opportunity: 0,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 4,
            opportunity: 0,
            diversity: 0,
        };
        let e = collide(a, b);
        assert_eq!(collision_energy(&e), a.score() + b.score());
        assert_eq!(collision_energy(&e), 7);
    }

    #[test]
    fn decay_total_score_equals_composed() {
        let a = BuleyProjection {
            waste: 2,
            opportunity: 1,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 1,
            opportunity: 1,
            diversity: 1,
        };
        let e = collide(a, b);
        let d = decay_products(&e);
        assert_eq!(
            d.waste.score() + d.action.score() + d.entropy.score(),
            collision_energy(&e),
        );
    }

    #[test]
    fn hexon_collision_triggers_at_one() {
        // Mirrors Gnosis.DigitalHadronCollider.hexon_collision_triggers_at_one
        let a = BuleyProjection {
            waste: 3,
            opportunity: 0,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 4,
            opportunity: 0,
            diversity: 0,
        };
        let e = collide(a, b);
        let trigger = collision_trigger(&e, tower_ceilings::HEXON);
        assert_eq!(trigger, Some(1));
    }

    #[test]
    fn triton_collision_within_triton_ceiling() {
        let a = BuleyProjection {
            waste: 1,
            opportunity: 0,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 0,
            opportunity: 2,
            diversity: 0,
        };
        let e = collide(a, b);
        let trigger = collision_trigger(&e, tower_ceilings::TRITON);
        assert_eq!(trigger, None);
    }

    #[test]
    fn require_collision_admits_at_ceiling() {
        let a = BuleyProjection {
            waste: 3,
            opportunity: 0,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 3,
            opportunity: 0,
            diversity: 0,
        };
        let e = collide(a, b);
        let result = require_collision_within_ceiling(e, tower_ceilings::HEXON);
        assert!(result.is_ok());
    }

    #[test]
    fn require_collision_rejects_over_ceiling() {
        let a = BuleyProjection {
            waste: 5,
            opportunity: 0,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 5,
            opportunity: 0,
            diversity: 0,
        };
        let e = collide(a, b);
        let result = require_collision_within_ceiling(e, tower_ceilings::HEXON);
        assert!(result.is_err());
        assert_eq!(result.unwrap_err().gate, "hadron-collider-trigger");
    }

    #[test]
    fn decagon_collision_triggers_at_ten() {
        // Mirrors decagon_collision_triggers_at_ten in Lean
        let a = BuleyProjection {
            waste: 10,
            opportunity: 0,
            diversity: 0,
        };
        let b = BuleyProjection {
            waste: 10,
            opportunity: 0,
            diversity: 0,
        };
        let e = collide(a, b);
        let trigger = collision_trigger(&e, tower_ceilings::DECAGON);
        assert_eq!(trigger, Some(10));
    }

    // ── Echolocation ────────────────────────────────────────────────

    #[test]
    fn emit_increments_score_by_one() {
        let b = BuleyProjection {
            waste: 5,
            opportunity: 0,
            diversity: 0,
        };
        let e = emit(b, BuleyFace::Waste);
        assert_eq!(e.emit_score, b.score() + 1);
        assert_eq!(e.emit_score, 6);
    }

    #[test]
    fn vacuum_emit_inside_hexon() {
        // Mirrors Gnosis.Echolocation.vacuum_emit_inside_hexon
        let event = echolocate(
            BuleyProjection::VACUUM,
            BuleyFace::Waste,
            tower_ceilings::HEXON,
        );
        assert!(event.probe_result.inside);
        assert_eq!(event.probe_result.contract_count, 0);
        assert_eq!(event.post_return, BuleyProjection::VACUUM);
    }

    #[test]
    fn hexon_edge_emit_triggers_one() {
        // Mirrors Gnosis.Echolocation.hexon_edge_emit_triggers_one
        let b = BuleyProjection {
            waste: 6,
            opportunity: 0,
            diversity: 0,
        };
        let event = echolocate(b, BuleyFace::Waste, tower_ceilings::HEXON);
        assert!(!event.probe_result.inside);
        assert_eq!(event.probe_result.contract_count, 1);
        // Round trip closes by the breathing identity
        assert_eq!(event.post_return, b);
    }

    #[test]
    fn trihexon_edge_at_wall() {
        let b = BuleyProjection {
            waste: 17,
            opportunity: 0,
            diversity: 0,
        };
        let event = echolocate(b, BuleyFace::Waste, tower_ceilings::TRIHEXON);
        assert!(event.probe_result.inside);
        assert_eq!(event.probe_result.contract_count, 0);
    }

    #[test]
    fn echolocation_round_trip_closes() {
        // Mirrors Gnosis.Echolocation.echolocation_round_trip_closes — the
        // breathing identity guarantees the post-return equals the source on
        // every face, every starting carrier, every ceiling.
        let samples = [
            BuleyProjection::VACUUM,
            BuleyProjection {
                waste: 1,
                opportunity: 0,
                diversity: 0,
            },
            BuleyProjection {
                waste: 2,
                opportunity: 3,
                diversity: 1,
            },
            BuleyProjection {
                waste: 18,
                opportunity: 0,
                diversity: 0,
            },
        ];
        let faces = [
            BuleyFace::Waste,
            BuleyFace::Opportunity,
            BuleyFace::Diversity,
        ];
        let ceilings = [
            tower_ceilings::TRITON,
            tower_ceilings::HEXON,
            tower_ceilings::ENNEON,
        ];
        for &b in &samples {
            for &face in &faces {
                for &ceiling in &ceilings {
                    let event = echolocate(b, face, ceiling);
                    assert_eq!(event.post_return, b);
                }
            }
        }
    }

    #[test]
    fn require_echolocation_admits_inside() {
        let b = BuleyProjection {
            waste: 4,
            opportunity: 0,
            diversity: 0,
        };
        let result =
            require_echolocation_within_ceiling(b, BuleyFace::Waste, tower_ceilings::HEXON);
        assert!(result.is_ok());
    }

    #[test]
    fn require_echolocation_rejects_violation() {
        let b = BuleyProjection {
            waste: 6,
            opportunity: 0,
            diversity: 0,
        };
        let result =
            require_echolocation_within_ceiling(b, BuleyFace::Waste, tower_ceilings::HEXON);
        assert!(result.is_err());
        assert_eq!(result.unwrap_err().gate, "echolocation-violation");
    }

    #[test]
    fn distance_to_wall_is_score_plus_one_minus_ceiling() {
        // Mirrors Gnosis.Echolocation.echolocation_distance_to_wall
        let b = BuleyProjection {
            waste: 8,
            opportunity: 0,
            diversity: 0,
        };
        let event = echolocate(b, BuleyFace::Waste, tower_ceilings::HEXON);
        // emit raised score to 9; ceiling is 6; distance is 9 - 6 = 3
        assert_eq!(event.probe_result.contract_count, 3);
    }
}
